const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      const invoice = mockInvoices.find(inv => inv.id === id);
      return invoice || null;
    }
  },
  Invoice: {
    customer: (parent, args, context) => {
      return mockCustomers.find(customer => customer.id === parent.customerId);
    },
    items: (parent, args, context) => {
      return mockInvoiceItems.filter(item => item.invoiceId === parent.id);
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    return {
      user: req.user
    };
  }
});

server.listen({ port: 4000 }).then(({ url }) => {
  console.log(`Server ready at ${url}`);
});